def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            aggregate = 0
            for a in range(5, 0, -1):
                for b in range(1, a + 5):
                    term = ((ratio - a) ** 7) / (a * b * 1.1 + 2)
                    aggregate += term * np.sin(ratio * b / (a + 2)) * np.cos(b * ratio / (a + 1))
            priority += np.log1p(aggregate) * np.exp((ratio - 10)/2)
            mod_factor = 0
            for c in range(1, 8):
                mod_factor += np.sin(c * ratio) / (c ** 1.2 + 0.5)
            priority += mod_factor ** 2
        elif 7 < ratio <= 10:
            S = 0
            for d in range(1, int(np.floor(ratio)) + 5):
                for e in range(1, d + 4):
                    factor = ((ratio - d) ** 4) * np.cos(ratio * e) / (e + 1.5)
                    S += np.tanh(factor) * 1.5
            priority = S + np.sqrt(ratio) * 15 - np.tanh(ratio - 7) * 3
            priority += np.sin(ratio * 2.3) * 2
        elif 4 <= ratio <= 7:
            summation = 0
            for f in range(1, 20):
                summation += ((ratio - 4) ** f) / (f * 2.0) * np.sin(f * ratio * 0.8)
            priority = (summation * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (7 - ratio)) * 2.0
            for g in range(1, 6):
                priority += np.cos(g * ratio * i) * ((ratio - 4) ** g) / (g + 1)
        elif 2 <= ratio < 4:
            val = 0
            for h in range(1, 15):
                val += ((4 - ratio) ** h) / (h ** 2 + 1) * np.cos(h * ratio)
            penalty = np.sqrt(item / (bin_cap + 1)) * 6 if bin_cap < item * 1.2 else np.cos(25 * ratio) * 3
            priority = val + penalty + np.exp(-2 / (ratio + 0.1))
            for j in range(1, 7):
                priority += np.sin(j * ratio * i * 0.9) * ((ratio - 2) ** j) / j
        elif 1 <= ratio < 2:
            summation = 0
            for k in range(1, 20):
                summation += ((2 - ratio) ** k) / (k * 5) * np.sin(k * item * 1.5)
            priority = summation
            if (i + int(item * 2.0)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.0) + 1.5)
            for l in range(1, 8):
                priority += ((2 - ratio) ** l) * np.cos(l * item * 1.7) * 0.8
        elif 0.5 <= ratio < 1:
            s_part = 0
            for m in range(1, 18):
                s_part += ((1 - ratio) ** m) / (m * 7) * np.cos(m * ratio * 2.5)
            priority = s_part + 1 / (bin_cap + 5)
            if int(item * 1.8) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for n in range(1, 9):
                priority += ((1 - ratio) ** n) / (n * 8) * np.cos(item * n * 1.3)
        else:
            base = 0
            for o in range(1, 15):
                base += ((0.5 - ratio) ** o) / (o * 9) * np.sin(o * item * 1.0)
            priority = base + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for p in range(1, 10):
                priority += ((0.5 - ratio) ** p) / (p * 10) * np.cos(item * p * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for q in range(1, 6):
            if (i + q) % 4 == 0:
                priority += np.sin(ratio * (i + q) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + q) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if priority < 0:
            priority = np.exp(priority) - 1
        if bin_cap % 2 == 0:
            priority += np.sqrt(bin_cap) * 0.5
        else:
            priority -= np.sqrt(bin_cap) * 0.5
        priorities[i] = priority
    return priorities
